        CancellationToken ct = default, ActionsDbContext? db = null)
    {
        var shouldDisposeContext = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            // 1. EntityMapper handles create/update detection
            // 2. Check for empty result (entity not found on update)
            // 3. AddRange for new entities
            // 4. Business logic (uniqueness → Fail, guards → Fail)
            // 5. try { SaveChangesAsync } catch { TOCTOU → Fail }
            // 6. Post-save best-effort side effects
            // 7. return Ok(mapResult)
        }
        finally
        {
            if (shouldDisposeContext)
                await db.DisposeAsync();
        }
    }
}

if (mapResult.NewItems.Count == 0 && mapResult.UpdatedItems.Count == 0)
    return CommandResult<EntityMapperResult<ActionEntity>>.Fail(
        "ACTION-001", $"Action with ID '{request.Id}' not found.", 404);

if (mapResult.NewItems.Count > 0)
    await db.Actions.AddRangeAsync(mapResult.NewItems, ct);

if (mapResult.UpdatedItems.Count > 0)
    db.Actions.UpdateRange(mapResult.UpdatedItems);

if (mapResult.DeletedItems.Count > 0)
    db.RemoveRange(mapResult.DeletedItems);

if (mapResult.NewItems.Count > 0)
{
    var slug = mapResult.NewItems[0].Slug;
    var slugExists = await db.Actions
        .AnyAsync(a => a.Slug == slug, ct);

    if (slugExists)
        return CommandResult<EntityMapperResult<ActionEntity>>.Fail(
            "ACTION-002", $"An action with slug '{slug}' already exists.", 409);
}

try
{
    await db.SaveChangesAsync(ct);
}
catch (DbUpdateException ex) when (
    ex.InnerException?.Message.Contains("ix_actions_slug", StringComparison.OrdinalIgnoreCase) == true
    || ex.InnerException?.Message.Contains("unique", StringComparison.OrdinalIgnoreCase) == true
       && ex.InnerException.Message.Contains("slug", StringComparison.OrdinalIgnoreCase) == true)
{
    return CommandResult<EntityMapperResult<ActionEntity>>.Fail(
        "ACTION-002", $"An action with slug '{request.Slug}' already exists.", 409);
}

// Redis cache invalidation
try
{
    await redisDb.KeyDeleteAsync(RedisKeySchema.Action(actionId.ToString()));
}
catch (Exception ex)
{
    logger.LogWarning(ex, "Failed to invalidate cache for action {ActionId}", actionId);
}

protected override async Task HandleValidatedRequestAsync(
    SaveActionRequest req, CancellationToken ct)
{
    var result = await saveCommand.ExecuteAsync(
        req, UserId, RequestLanguageId, DefaultLanguageId, ct);
    if (!result.Succeeded)
    {
        await SendProblemAsync(result.Error!.Code, result.Error.StatusCode, result.Error.Message, ct);
        return;
    }

    var mapResult = result.Value!;
    var isNew = mapResult.NewItems.Count > 0;
    var entity = isNew ? mapResult.NewItems[0] : mapResult.UpdatedItems[0];

    var eventName = isNew ? "action.created" : "action.updated";
    await auditService.LogAsync(eventName, "Action", entity.Id,
        new { req.Name, req.Slug }, ct);

    if (isNew)
        await Send.CreatedAtAsync<GetActionEndpoint>(
            new { id = entity.Id },
            new SaveActionResponse(entity.Id), cancellation: ct);
    else
        await Send.OkAsync(new SaveActionResponse(entity.Id), ct);
}

public class DeleteWorkflowCommand(IDbContextFactory<ActionsDbContext> dbContextFactory)
{
    public async Task<CommandResult> ExecuteAsync(
        Guid[] keys, CancellationToken ct = default, ActionsDbContext? db = null)
    {
        var shouldDisposeContext = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            // Protection check — returns structured error
            var protectedWorkflows = await db.Workflows
                .AsNoTracking()
                .Where(w => keys.Contains(w.Id) && w.IsSystemProtected)
                .Select(w => w.Name)
                .ToListAsync(ct);

            if (protectedWorkflows.Count > 0)
                return CommandResult.Fail("WORKFLOW-001",
                    $"Cannot delete protected workflows: {string.Join(", ", protectedWorkflows)}", 422);

            // Explicit transaction — prevents partial deletes on failure
            await using var tx = await db.Database.BeginTransactionAsync(ct);

            await db.WorkflowSteps
                .Where(s => keys.Contains(s.WorkflowId))
                .ExecuteDeleteAsync(ct);

            await db.WorkflowTriggers
                .Where(t => keys.Contains(t.WorkflowId))
                .ExecuteDeleteAsync(ct);

            await db.Workflows
                .Where(w => keys.Contains(w.Id))
                .ExecuteDeleteAsync(ct);

            await tx.CommitAsync(ct);
            return CommandResult.Success;
        }
        finally
        {
            if (shouldDisposeContext)
                await db.DisposeAsync();
        }
    }
}

