public class DeleteActionsCommand(IDbContextFactory<ActionsDbContext> dbContextFactory)
{
    public async Task<CommandResult> ExecuteAsync(
        Guid[] keys, Guid userId, CancellationToken ct = default, ActionsDbContext? db = null)
    {
        var shouldDisposeContext = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            var actions = await db.Actions
                .Where(a => keys.Contains(a.Id))
                .ToListAsync(ct);

            if (actions.Count != keys.Length)
                return CommandResult.Fail("ACTION-001", "One or more actions not found.", 404);

            foreach (var action in actions)
            {
                action.IsDeleted = true;
                action.DeletedDate = DateTime.UtcNow;
                action.DeletedById = userId;
            }

            await db.SaveChangesAsync(ct);
            return CommandResult.Success;
        }
        finally
        {
            if (shouldDisposeContext)
                await db.DisposeAsync();
        }
    }
}

public class ActivateComplianceProfileCommand(
    IDbContextFactory<ActionsDbContext> dbContextFactory,
    ILogger<ActivateComplianceProfileCommand> logger)
{
    public async Task<CommandResult> ExecuteAsync(
        Guid profileId, Guid userId,
        CancellationToken ct, ActionsDbContext? db = null)
    {
        var shouldDisposeContext = db is null;
        db ??= await dbContextFactory.CreateDbContextAsync(ct);
        try
        {
            var profile = await db.ComplianceProfiles
                .FirstOrDefaultAsync(p => p.Id == profileId, ct);

            if (profile is null)
                return CommandResult.Fail("PROFILE-001", "Compliance profile not found.", 404);

            if (profile.Status != ComplianceProfileStatus.Draft)
                return CommandResult.Fail("PROFILE-002", "Profile is not in draft status.", 422);

            var now = DateTime.UtcNow;
            profile.Status = ComplianceProfileStatus.Active;
            profile.ActivatedAt = now;
            profile.UpdatedDate = now;
            profile.UpdatedById = userId;
            await db.SaveChangesAsync(ct);
            return CommandResult.Success;
        }
        finally
        {
            if (shouldDisposeContext)
                await db.DisposeAsync();
        }
    }
}

